import React from 'react';

function Project({ title, description, technologies, features, liveDemo, github }) {
  return (
    <div className="project-card">
      <h2>{title}</h2>
      <p>{description}</p>
      <ul>
        <li><strong>Technologies Used:</strong> {technologies}</li>
        <li><strong>Features:</strong> {features}</li>
      </ul>
      <div className="project-links">
        <a href={liveDemo} target="_blank" rel="noopener noreferrer">Live Demo</a>
        <a href={github} target="_blank" rel="noopener noreferrer">View Code on GitHub</a>
      </div>
    </div>
  );
}

export default Project;
